import pytest
import requests

def test_unauthenticated_request_to_create_policy_document_returns_401(
    base_url,
):
    payload = {
        "title": "Unauthenticated Policy",
        "content": "Should be rejected.",
        "effective_date": "2025-01-01",
        "category": "leave",
    }
    # Plain session – no auth header injected
    resp = requests.post(
        f"{base_url}/policy-documents",
        json=payload,
        timeout=10,
    )
    assert resp.status_code == 401, (
        f"Unauthenticated request must return 401; got {resp.status_code}"
    )

import pytest

def test_forbidden_role_cannot_create_policy_document_returns_403(
    employee_client,   # <fixture> returns authenticated requests.Session for role:employee
    base_url,
):
    payload = {
        "title": "Forbidden Policy Attempt",
        "content": "An employee must not create policy documents.",
        "effective_date": "2025-01-01",
        "category": "leave",
    }
    resp = employee_client.post(f"{base_url}/policy-documents", json=payload)
    assert resp.status_code == 403, (
        f"Employee role must be forbidden (403); got {resp.status_code}"
    )
